import sys
from collections import defaultdict, OrderedDict

class Node:
    def __init__(self, key, val, count):
        self.key = key
        self.val = val
        self.count = count

class LFUCache:

    def __init__(self, capacity: int):
        self.capacity = capacity
        self.key2node = {}
        self.count2node = defaultdict(OrderedDict)
        self.minCount = None

    def get(self, key: int) -> int:
        if key not in self.key2node:
            return -1
        node = self.key2node[key]
        del self.count2node[node.count][key]

        # if there are no nodes with that count anymore, we need to update minCount
        if not self.count2node[node.count]:
            del self.count2node[node.count]
            if node.count == self.minCount:
                self.minCount += 1

        node.count += 1
        self.count2node[node.count][key] = node

        return node.val

    def put(self, key: int, value: int) -> None:
        if not self.capacity:
            return

        if key in self.key2node:
            self.key2node[key].val = value
            self.get(key)  # increase the count
            return

        if len(self.key2node) == self.capacity:
            # remove the LFU node
            k, n = self.count2node[self.minCount].popitem(last=False)
            del self.key2node[k]

        self.count2node[1][key] = self.key2node[key] = Node(key, value, 1)
        self.minCount = 1

def main():
    it = iter(sys.stdin.read().split())
    n = int(next(it))
    cache = LFUCache(0)
    for _ in range(n):
        op = next(it)
        if op == 'get':
            key = int(next(it))
            print(cache.get(key))
        elif op == 'put':
            key = int(next(it))
            val = int(next(it))
            cache.put(key, val)

if __name__ == '__main__':
    main()

