#include <bits/stdc++.h>
using namespace std;

struct Node {
    int key, val, count;
    Node(int k, int v, int c) : key(k), val(v), count(c) {}
};

class LFUCache {
private:
    int capacity;
    unordered_map<int, Node*> key2node;
    unordered_map<int, list<Node*>> count2node;
    int minCount;

public:
    LFUCache(int capacity) : capacity(capacity), minCount(0) {}

    int get(int key) {
        if (key2node.find(key) == key2node.end()) return -1;
        Node* node = key2node[key];
        count2node[node->count].remove(node);
        if (count2node[node->count].empty()) {
            count2node.erase(node->count);
            if (node->count == minCount) minCount++;
        }
        node->count++;
        count2node[node->count].push_back(node);
        return node->val;
    }

    void put(int key, int value) {
        if (!capacity) return;
        if (key2node.find(key) != key2node.end()) {
            key2node[key]->val = value;
            get(key);
            return;
        }
        if (key2node.size() == capacity) {
            Node* node = *count2node[minCount].begin();
            key2node.erase(node->key);
            count2node[minCount].pop_front();
            if (count2node[minCount].empty()) count2node.erase(minCount);
        }
        Node* node = new Node(key, value, 1);
        key2node[key] = node;
        count2node[1].push_back(node);
        minCount = 1;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    LFUCache cache(0);
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        if (op == "get") {
            int key;
            cin >> key;
            cout << cache.get(key) << '\n';
        } else {
            int key, val;
            cin >> key >> val;
            cache.put(key, val);
        }
    }
    return 0;
}
